(() => {
    interface CircularTuple {
      tuple: [bigint, CircularTuple?];
    }
    return {build: () => createValidate<CircularTuple>(), buildErrors: () => noErrs(createGetValidationErrors<CircularTuple>())};
  })()

c(z.lazy(() => {
    const schema: z.ZodType = z.object({
      tuple: z.tuple([z.bigint()]).rest(z.lazy(() => schema) as z.ZodType),
    });
    return schema;
  }))

c(
    Type.Recursive((This) =>
      Type.Object({
        tuple: Type.Union([Type.Tuple([Type.BigInt()]), Type.Tuple([Type.BigInt(), This])]),
      })
    )
  )
